-- ============================================================
-- STEP 1: Dataset
-- ============================================================
CREATE SCHEMA IF NOT EXISTS `phrasal-method-484415-g7.bank_data`
OPTIONS (location = 'EU');

-- ============================================================
-- STEP 2: Tabelle
-- ============================================================

CREATE TABLE IF NOT EXISTS `phrasal-method-484415-g7.bank_data.pacchetti` (
  pacchetto_id STRING NOT NULL, nome STRING NOT NULL, segmento STRING,
  canone_mensile NUMERIC, cashback_pct NUMERIC, includi_carta BOOL,
  includi_fido BOOL, data_lancio DATE
);

CREATE TABLE IF NOT EXISTS `phrasal-method-484415-g7.bank_data.clienti` (
  cliente_id STRING NOT NULL, nome STRING NOT NULL, cognome STRING NOT NULL,
  codice_fiscale STRING, data_nascita DATE, genere STRING, citta STRING,
  regione STRING, email STRING, segmento STRING, pacchetto_id STRING,
  data_apertura DATE, stato STRING, aum NUMERIC, reddito_annuo NUMERIC,
  score_credito INT64
);

CREATE TABLE IF NOT EXISTS `phrasal-method-484415-g7.bank_data.conti` (
  conto_id STRING NOT NULL, cliente_id STRING NOT NULL, iban STRING,
  tipo_conto STRING, valuta STRING, saldo NUMERIC, fido_accordato NUMERIC,
  data_apertura DATE, stato STRING
);

CREATE TABLE IF NOT EXISTS `phrasal-method-484415-g7.bank_data.movimenti` (
  movimento_id STRING NOT NULL, conto_id STRING NOT NULL,
  data_operazione DATE NOT NULL, tipo_operazione STRING,
  importo NUMERIC NOT NULL, saldo_dopo NUMERIC, descrizione STRING,
  categoria STRING, canale STRING, stato STRING
);

CREATE TABLE IF NOT EXISTS `phrasal-method-484415-g7.bank_data.reclami` (
  reclamo_id STRING NOT NULL, cliente_id STRING NOT NULL,
  data_apertura DATETIME NOT NULL, data_chiusura DATETIME,
  canale_apertura STRING, categoria STRING, descrizione STRING,
  priorita STRING, stato STRING, esito STRING,
  rimborso_importo NUMERIC, soddisfazione INT64
);

